mapper.select:
SELECT r.id, r.resource_uuid, r.space_id, r.parent_id, r.resource_type, r.name, r.name_normalized, r.extension, r.size_bytes, r.object_id, r.path_cache, r.owner_user_id, r.is_deleted, r.deleted_at, r.created_at, r.updated_at FROM resources r JOIN users u ON r.owner_user_id = u.id WHERE u.user_uuid = #{userUuid} AND r.parent_id = #{parentId} AND r.is_deleted = 0
AND r.name_normalized LIKE CONCAT('%', #{keyword}, '%')
ORDER BY CASE WHEN r.resource_type = 'folder' THEN 0 ELSE 1 END ASC, r.name_normalized ASC, r.id ASC LIMIT #{offset}, #{pageSize}

SELECT COUNT(1)
FROM resources
WHERE parent_id = #{parentId}
  AND name_normalized = #{nameNormalized}
  AND is_deleted = 0
